//! foil-rank-probe — MEASURE the FOIL axis on a REAL rwkv7-0.4b activation.
//!
//! Thesis under test: the decode DOT descends toward the cache via FOIL — if the
//! hidden state (the activation the lm_head dot multiplies) lives in few
//! "resonances" (low effective rank k ≪ D), the D-term dot foils to k terms. This
//! is the prerequisite for the cheap-interference axis (1-bit XNOR is exact only
//! in a low-rank / aligned basis). Here we CAPTURE the real final-LayerNorm hidden
//! state of rwkv7-0.4b (D = 1024) and measure:
//!   (a) effective rank via participation ratio (Σλ)²/Σλ² over per-dim energy,
//!   (b) how many dims hold 90% of the L2 energy,
//!   (c) winning-token lm_head cosine alignment (interference threshold ≥ 0.4).
//!
//! Real weights, real forward. Prompt tokens are the RWKV-World encoding of a real
//! sentence (default: "The capital of France is").
//!
//! Run:  cargo run --release --bin foil-rank-probe -- <knot_path> [tok0 tok1 ...]

use distributed_inference::loader::KnotWeights;
use distributed_inference::model_rwkv7::RWKV7Pipeline;
use std::sync::Arc;

fn participation_ratio(energy: &[f64]) -> f64 {
    let s: f64 = energy.iter().sum();
    let s2: f64 = energy.iter().map(|e| e * e).sum();
    if s2 == 0.0 {
        0.0
    } else {
        (s * s) / s2
    }
}

/// Smallest number of dims (by descending energy) holding >= `frac` of total.
fn dims_for_energy(energy: &[f64], frac: f64) -> usize {
    let total: f64 = energy.iter().sum();
    if total == 0.0 {
        return 0;
    }
    let mut sorted = energy.to_vec();
    sorted.sort_by(|a, b| b.partial_cmp(a).unwrap());
    let mut acc = 0.0;
    for (i, e) in sorted.iter().enumerate() {
        acc += e;
        if acc >= frac * total {
            return i + 1;
        }
    }
    energy.len()
}

fn cosine(a: &[f32], b: &[f32]) -> f64 {
    let mut dot = 0.0f64;
    let mut na = 0.0f64;
    let mut nb = 0.0f64;
    for i in 0..a.len() {
        dot += a[i] as f64 * b[i] as f64;
        na += (a[i] as f64).powi(2);
        nb += (b[i] as f64).powi(2);
    }
    if na == 0.0 || nb == 0.0 {
        0.0
    } else {
        dot / (na.sqrt() * nb.sqrt())
    }
}

fn per_dim_report(tag: &str, x: &[f32], d: usize) {
    let energy: Vec<f64> = x.iter().map(|&v| (v as f64).powi(2)).collect();
    let l2: f64 = energy.iter().sum::<f64>().sqrt();
    let pr = participation_ratio(&energy);
    let d50 = dims_for_energy(&energy, 0.50);
    let d90 = dims_for_energy(&energy, 0.90);
    let d99 = dims_for_energy(&energy, 0.99);
    // Top dims by energy.
    let mut idx: Vec<usize> = (0..d).collect();
    idx.sort_by(|&a, &b| energy[b].partial_cmp(&energy[a]).unwrap());
    let total: f64 = energy.iter().sum();
    let top10: f64 = idx.iter().take(10).map(|&i| energy[i]).sum::<f64>() / total;
    println!("[{tag}] D={d}  ||x||_2={l2:.4}");
    println!(
        "  effective rank (participation ratio) k = {:.2}   (k/D = {:.3})",
        pr,
        pr / d as f64
    );
    println!("  dims holding 50% / 90% / 99% energy: {d50} / {d90} / {d99}  (of {d})");
    println!("  top-10 dims hold {:.1}% of the L2 energy", top10 * 100.0);
}

fn main() {
    let mut args = std::env::args().skip(1);
    let knot_path = args.next().unwrap_or_else(|| {
        "/private/tmp/claude-501/-Users-buley-Documents-Code-monorepo/dab2040a-b9df-4f6b-8f0f-d96780b01544/scratchpad/rwkv7-0.4b.knot".to_string()
    });
    let mut tokens: Vec<u32> = args.filter_map(|s| s.parse::<u32>().ok()).collect();
    if tokens.is_empty() {
        // "The capital of France is" under the RWKV-World tokenizer.
        tokens = vec![6699, 51128, 4706, 44312, 4600];
    }

    eprintln!("foil-rank-probe: knot={knot_path} prompt_tokens={tokens:?}");
    let knot = KnotWeights::load(&knot_path).expect("knot load");
    let cfg = knot.config.clone().expect("knot has config");
    let d = cfg.hidden_dim;
    let vocab = cfg.vocab_size;
    eprintln!(
        "  arch={} hidden_dim={} layers={} vocab={}",
        cfg.arch, d, cfg.num_layers, vocab
    );

    let backend = Arc::clone(&knot.backend);
    let mut p = RWKV7Pipeline::from_knot(&cfg, backend);

    let mut logits = vec![0f32; vocab];
    let mut acts: Vec<Vec<f32>> = Vec::new();
    for &tok in &tokens {
        let normed = p.forward_one_capture(tok, &mut logits);
        acts.push(normed);
    }

    // The decode activation predicting the NEXT token is the last step's hidden.
    let last = acts.last().unwrap().clone();

    // Winning token + cosine alignment against its lm_head row.
    let (argmax, &max_logit) = logits
        .iter()
        .enumerate()
        .max_by(|a, b| a.1.partial_cmp(b.1).unwrap())
        .unwrap();
    let nan = logits.iter().filter(|x| x.is_nan()).count();
    let lm_row = p.lm_head_row(argmax);
    let cos = cosine(&last, &lm_row);

    println!("\n================ FOIL RANK PROBE — rwkv7-0.4b (REAL weights, real forward) ================");
    println!(
        "prompt tokens = {} steps, NaN logits = {}/{}, argmax next-token id = {} (logit {:.3})",
        tokens.len(),
        nan,
        vocab,
        argmax,
        max_logit
    );
    println!("\n-- (a)(b) effective rank of the decode activation (final-LN hidden, pre lm_head) --");
    per_dim_report("last-step activation", &last, d);

    println!("\n-- per-step effective rank across the prompt (real dynamics) --");
    for (t, a) in acts.iter().enumerate() {
        let energy: Vec<f64> = a.iter().map(|&v| (v as f64).powi(2)).collect();
        let pr = participation_ratio(&energy);
        let d90 = dims_for_energy(&energy, 0.90);
        println!(
            "  step {t} (tok {}): PR-rank k={:.1}  (k/D={:.3})  90%-energy dims={d90}",
            tokens[t],
            pr,
            pr / d as f64
        );
    }

    println!("\n-- (c) winning-token lm_head alignment --");
    println!(
        "  cos(activation, lm_head_row[{argmax}]) = {:.4}   (interference threshold >= 0.40 -> {})",
        cos,
        if cos.abs() >= 0.40 { "MET" } else { "not met" }
    );

    // Dump the T×D activation matrix (f32 LE) for a numpy SVD cross-check of the
    // spectral effective rank of the activation SUBSPACE.
    let out_path = "/private/tmp/claude-501/-Users-buley-Documents-Code-monorepo/dab2040a-b9df-4f6b-8f0f-d96780b01544/scratchpad/rwkv7_acts.f32";
    let mut bytes: Vec<u8> = Vec::with_capacity(acts.len() * d * 4);
    for a in &acts {
        for &v in a {
            bytes.extend_from_slice(&v.to_le_bytes());
        }
    }
    std::fs::write(out_path, &bytes).ok();
    // Also dump the winning lm_head row for external alignment checks.
    let mut lmb: Vec<u8> = Vec::with_capacity(d * 4);
    for &v in &lm_row {
        lmb.extend_from_slice(&v.to_le_bytes());
    }
    std::fs::write(
        "/private/tmp/claude-501/-Users-buley-Documents-Code-monorepo/dab2040a-b9df-4f6b-8f0f-d96780b01544/scratchpad/rwkv7_lmrow.f32",
        &lmb,
    )
    .ok();
    println!(
        "\nwrote {} activation rows x {} dims to {out_path} (f32 LE) for numpy SVD cross-check",
        acts.len(),
        d
    );
}
